where.if:
AND (
    j.work_mode = #{workMode}
    OR (#{workMode} = 'ONSITE' AND j.work_mode IN ('现场办公', '线下办公'))
    OR (#{workMode} = 'REMOTE' AND j.work_mode IN ('远程协同', '远程办公'))
    OR (#{workMode} = 'HYBRID' AND j.work_mode IN ('混合办公', '混合协同'))
)

AND (
    j.duration_type = #{durationType}
    OR (#{durationType} = 'SHORT_TERM' AND j.duration_type = '短期实习')
    OR (#{durationType} = 'LONG_TERM' AND j.duration_type IN ('长期实习', '实习'))
    OR (#{durationType} = 'FULL_TIME' AND j.duration_type IN ('全职', '校招全职'))
)

mapper.select:
SELECT , COALESCE(app_stat.applicationCount, 0) AS applicationCount
LEFT JOIN ( SELECT job_id, COUNT(1) AS applicationCount FROM application_record GROUP BY job_id ) app_stat ON app_stat.job_id = j.id
ORDER BY j.update_time DESC, j.id DESC LIMIT #{offset}, #{pageSize}
